SourceCode.Declaration:
/// <summary>
/// Represents the ETGSPAIN Unsold Journal table which manages journal entries for unsold inventory transactions.
/// </summary>
/// <remarks>
/// This class handles the initialization of unsold journal entries, provides lookup functions for journal entries by their ID, and checks for the existence of related import log records.
/// </remarks>
public class ETGSPAINUnsoldJournalTable extends common
{
}

Method.Source:
/// <summary>
/// Initializes default values for a new unsold journal entry, including generating a journal ID using the number sequence system.
/// </summary>
public void initValue()
{
    SysLastValue            nextNumSeq;
    NumberSeq               numberSeq;
    Num                     lastNumber;
    NumberSequenceReference numberSequenceReference;
    ;

    super();

    nextNumSeq.value = connull();
    numberSequenceReference = NumberSeqModuleInventory::ETGSPAINnumRefETGSPAINUnsoldJournalId();
    numberSeq = NumberSeq::newGetNumFromCode(numberSequenceReference.numberSequenceTable().NumberSequence,
                                        NumberSeqScopeFactory::createDefaultScope(),
                                        true,
                                        false,
                                        nextNumSeq,
                                        true);
    if (numberSeq)
    {
        [lastNumber]    = nextNumSeq.value;
        this.JournalId  = lastNumber;
    }
}

/// <summary>
/// Finds an unsold journal entry by its ID.
/// </summary>
/// <param name="_journalId">The ID of the unsold journal entry.</param>
/// <param name="_forUpdate">Boolean indicating if the record is for update.</param>
/// <returns>Returns the journal entry if found; otherwise, null.</returns>
static ETGSPAINUnsoldJournalTable find(ETGSPAINUnsoldJournalId  _journalId,
                                        boolean                 _forUpdate = false)
{
    ETGSPAINUnsoldJournalTable etgspainUnsoldJournalTable;

    if (_journalId)
    {
        if (_forUpdate)
        {
            etgspainUnsoldJournalTable.selectForUpdate(_forUpdate);
        }

        select firstonly etgspainUnsoldJournalTable
            index hint JournalIdx
            where etgspainUnsoldJournalTable.JournalId == _journalId;
    }

    return etgspainUnsoldJournalTable;
}

/// <summary>
/// Checks if a journal entry exists by its ID.
/// </summary>
/// <param name="_journalId">The ID of the unsold journal entry.</param>
/// <returns>True if the journal exists, otherwise false.</returns>
static boolean exist(ETGSPAINUnsoldJournalId  _journalId)
{
    return _journalId && (select firstonly RecId from ETGSPAINUnsoldJournalTable
                                index hint JournalIdx
                                where ETGSPAINUnsoldJournalTable.JournalId == _journalId).RecId != 0;
}

    /// <summary>
    /// Checks if there is a related import log entry for this journal.
    /// </summary>
    /// <returns>True if an import log entry exists, otherwise false.</returns>
    public boolean hasETGSPAINUnsoldJournalImportLogTable()
     {
		return ETGSPAINUnsoldJournalImportLogTable::existJournalId(this.JournalId);
	}
